var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"POOR_NPC_NULL_BOSS","text":{"KOREA":"크으윽… 내가… 엘릭서를 쓰고도 힘에서 밀리다니…?","JPN":"くううっ……俺が……エリクサーを飲んでも力で負けるとは……？","ENG":"Kggh... I lost... even with the Elixir...?","TWN":"唔…我用了聖水還是打不過你…？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"무술 실력을 보아하니 그대는 백서의 사람이 아닌 것 같구려.","JPN":"武術の実力から見ると、貴殿は白西の者ではないようですね。","ENG":"Observing your skills, I have confirmed that you are not with White West.","TWN":"在下看你的武功實力，似乎不是白西的人。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"묻겠소. 누가 날 데려오라고 사주한 것이오?","JPN":"問いましょう。誰から自分を連れてくるようにと頼まれたのですか？","ENG":"Answer me. Who ordered you to kidnap me?","TWN":"敢問，是誰指使你把我抓來這裡的？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"POOR_NPC_NULL_BOSS","text":{"KOREA":"머, 멍청하긴. 그렇게 물어보면 누가 대답을 해주겠대?","JPN":"ば、バカだな。そう聞かれても答えるわけにはいかねえよ。","ENG":"H-how stupid are you? You think I'm gonna answer that?!","TWN":"\\n當，當我傻子嗎？你問我，我就要回答你嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"POOR_NPC_NULL_BOSS","text":{"KOREA":"으아악…!!!","JPN":"ぐわああっ……！！！","ENG":"Aaack...!","TWN":"呃啊啊啊…！！！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"이렇게 하면 말할 거요?","JPN":"こうすれば答えていただけますか？","ENG":"Does this make you feel more inclined to answer?","TWN":"那這樣呢？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"POOR_NPC_NULL_BOSS","text":{"KOREA":"마… 말… 못해… 말했다간 난 죽은 목숨이라고…","JPN":"は……話せ……ねえ……話したら俺は死ぬ……","ENG":"N-never...! I'm a dead man if I tell you anything...","TWN":"我…我…我不能說…要是我告訴你的話，我也別想活命…"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"본인은 타혈법에 능통하다오.","JPN":"自分は点穴に精通しています。","ENG":"I have mastered nerve strikes.","TWN":"在下精通穴道。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"바란다면 죽음보다 더한 아홉 가지 고통을 동시에 느끼게 해주겠소.","JPN":"お望みなら、死よりもむごい9つの苦痛を同時に感じさせてあげましょう。","ENG":"I shall let you feel nine kinds of pain far worse than death itself, if that is what you wish.","TWN":"你想試試的話，在下可以讓你同時感受到九種生不如死的痛苦。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"POOR_NPC_NULL_BOSS","text":{"KOREA":"으… 으… 절대로…","JPN":"う……う……絶対に……","ENG":"Ngh... I'll... never–","TWN":"呃…呃…我不能…"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"POOR_NPC_NULL_BOSS","text":{"KOREA":"끼야아아아아아아앗!!!!","JPN":"ぎゃあああああああっ！！！！","ENG":"AAAAAGH!!!!","TWN":"呃啊啊啊啊啊啊！！！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"마지막까지 실토를 하지 않다니… 그대의 인내심은 인정할 만 하구려.","JPN":"最後まで口を割らないとは……貴殿の忍耐力は認めざるを得ません。","ENG":"Not talking, I see... I admire your tolerance to pain.","TWN":"嘴巴真緊…我承認你的忍耐力可佳。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"POOR_NPC_NULL_BOSS","text":{"KOREA":"끄으으으… 윽…","JPN":"くううう……うっ……","ENG":"Krrrrgh... Ngh.","TWN":"呃呃呃…呃…"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"POOR_NPC_NULL_B","text":{"KOREA":"두목이… 아까부터 계속 뭔가 말하려는 것 같았는데…","JPN":"親分……さっきからずっと何か話そうとしてたみたいだったけど……","ENG":"I think... boss was trying to say something...","TWN":"老大…好像有什麼話想說…"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"POOR_NPC_NULL_A","text":{"KOREA":"입만 뻐끔거리며 고통스러워하다가 기절했어.","JPN":"口だけ動かしながら苦しんで気絶しちまった。","ENG":"He kept mouthing something, but fainted due to the pain.","TWN":"但他好像來不及說，就痛到暈過去了。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그대들도 덤빌 셈이요?","JPN":"貴殿らもかかってくるつもりですか？","ENG":"Do you wish to challenge me as well?","TWN":"你們也想挑戰嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"POOR_NPC_NULL_A","text":{"KOREA":"그럴 리가요! 다시는 까불지 않겠습니다!","JPN":"まさか！　二度とふざけた真似などいたしません！","ENG":"Not at all! We wouldn't dare!","TWN":"當然不想！小的不敢放肆！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L30_1","type":"dialog","speaker":"POOR_NPC_NULL_B","text":{"KOREA":"저희를 고문하셔도 아는 게 하나도 없어서 말 못해요! 제발 목숨만 살려만 주세요!","JPN":"俺たちを拷問しても、話せることはひとつもありません！　どうか命だけは！","ENG":"Even if you torture us, we really don't know anything! Please, have mercy!","TWN":"女俠饒命，就算你嚴刑逼供也沒用，我們真的什麼也不知道！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"구태여 불필요한 살생은 하지 않소.","JPN":"不要な殺傷はしません。","ENG":"I do not kill if unnecessary.","TWN":"在下不會濫殺無辜。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"대신 부탁이나 하나 하지.","JPN":"その代わり、一つだけ頼みましょう。","ENG":"In exchange, I shall request something from you.","TWN":"不過在下想請二位幫個忙。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"POOR_NPC_NULL_A","text":{"KOREA":"무, 물론이죠! 사… 상납금이라도 바칠까요?","JPN":"も、もちろんです！　上納金でも差し上げましょうか？","ENG":"O-of course! D-do you want us to give you money?","TWN":"在，在所不辭！你…你要錢嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"POOR_NPC_NULL_B","text":{"KOREA":"말씀만 하세요! 개처럼 기라면 기고 짖으라면 짖겠습니다!","JPN":"犬みたいに吠えろとか、四つん這いになれとか何でも言ってください！","ENG":"Just say the word! We'll walk on all fours and bark like dogs if that's what you want from us!","TWN":"女俠儘管說！要我學狗叫都可以！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"카운터 아카데미가 어디에 있는지 안내 좀 해주겠소?","JPN":"カウンターアカデミーがどこにあるのか、案内してもらえますか？","ENG":"Could you guide me to the Counter Academy?","TWN":"可以告訴在下，制裁者學院要怎麼走嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"POOR_NPC_NULL_A","text":{"KOREA":"…네?","JPN":"……はい？","ENG":"...What?","TWN":"…蛤？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"POOR_NPC_NULL_A","text":{"KOREA":"이쪽입니다. 이 길로 쭉 가시면 카운터 아카데미의 정문이 나올 거예요.","JPN":"こっちです。この道を真っすぐ行くと、カウンターアカデミーの正門ですよ。","ENG":"It's this way. Go straight down this path, and you'll arrive at the Academy's main gate.","TWN":"往這裡直走，就可以看到制裁者學院的正門。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"고맙구려.","JPN":"ありがとうございます。","ENG":"Your assistance is appreciated.","TWN":"多謝。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그대들은 더 동행하지 않는 거요?","JPN":"貴殿らはもう同行しないのですか？","ENG":"Are you not accompanying me?","TWN":"你們不與在下同去嗎？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"POOR_NPC_NULL_A","text":{"KOREA":"하하… 그라운드 원의 중심부는 치안이 삼엄해서요.","JPN":"ハハ……グラウンド・ワンの中心部は警備が厳しいんで。","ENG":"Haha... Central Ground One's security is pretty strict.","TWN":"哈哈…G1市中心的戒備森嚴。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"POOR_NPC_NULL_B","text":{"KOREA":"저희는 신분증도 없는 처지라 눈에 띄는 순간 경찰에 잡혀갈 거예요.","JPN":"俺たちは身分証明書さえないから、警察の目に留まると捕まっちゃいますよ。","ENG":"We don't have any ID, so we'll get caught the second we show our faces.","TWN":"我們沒有身分證，要是被發現就會立刻被抓到警察局。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…그렇소?","JPN":"……然様ですか。","ENG":"...Is that so?","TWN":"…是嗎？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"POOR_NPC_NULL_A","text":{"KOREA":"뭔가 더 요구할 건 없으신가요?","JPN":"他に、やって欲しいことはないんですか？","ENG":"Is there anything else we can do for you?","TWN":"還有其他需要我們效勞的地方嗎？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"POOR_NPC_NULL_B","text":{"KOREA":"말씀만 하세요, 누님.","JPN":"何なりと言ってください、姉貴。","ENG":"Just say the word, ma'am.","TWN":"女俠請說。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"앞으로는 악인의 뜻에 휘둘리지 말고 떳떳한 일을 하며 살아가시오.","JPN":"これからは悪人の感情に振り回されず、堂々と働きながら生きてください。","ENG":"Live an honest life and do not get swayed by the will of the wicked.","TWN":"往後不要再跟壞人一起為非作歹，要做正經事。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그것이 내 마지막 요구라오.","JPN":"それが自分の最後の頼みです。","ENG":"That is my last request to you.","TWN":"這是在下最後的要求。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"POOR_NPC_NULL_A","text":{"KOREA":"너… 나랑 같은 생각하냐?","JPN":"お前さ……俺と同じこと考えてる？","ENG":"Um... Are you thinking what I'm thinking?","TWN":"你…你和我想的一樣嗎？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"POOR_NPC_NULL_B","text":{"KOREA":"아마도.","JPN":"たぶんな。","ENG":"I think so.","TWN":"應該是。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"POOR_NPC_NULL_A","text":{"KOREA":"엄청 무섭긴 한데… 나 반한 것 같아.","JPN":"めっちゃ怖い人だけど……俺、惚れちゃったかも。","ENG":"She's a little scary... but I think I'm falling for her.","TWN":"雖然很嚇人…但這是什麼悸動的感覺？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"POOR_NPC_NULL_B","text":{"KOREA":"이런 게… 사랑인 걸까?","JPN":"これが……恋なのかな？","ENG":"Is this... what love feels like?","TWN":"難道…這就是愛情？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};